#include<bits/stdc++.h>
using namespace std;
int id,t,n,m,x,y;
vector<int> mp[1000010];
bool vis[1000010][2],f[1000010][2],vis1[1000010],flag;
bool dfs(int x,int v)
{
    if(x==(::y)&&v==0)
    {
        return true;
    }
    if(vis[x][v])
    {
        return f[x][v];
    }
    vis[x][v]=true;
    vis1[x]=true;
    f[x][v]=false;
    int cnt=0;
    for(int i:mp[x])
    {
        if(vis1[i])
        {
            cnt++;
        }
        f[x][v]|=dfs(i,1-v);
    }
    if(cnt>1)
    {
        flag=true;
    }
    return f[x][v];
}
int main()
{
    int id,t;
    scanf("%d%d",&id,&t);
    while(t--)
    {
        flag=false;
        memset(vis,0,sizeof(vis));
        memset(vis1,0,sizeof(vis1));
        scanf("%d%d%d%d",&n,&m,&x,&y);
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        for(int i=1;i<=m;i++)
        {
            int x,y;
            scanf("%d%d",&x,&y);
            mp[x].push_back(y);
            mp[y].push_back(x);
        }
        if(dfs(x,1)&&flag)
        {
            printf("Yes\n");
        }
        else
        {
            printf("No\n");
        }
    }
    return 0;
}
